 1→/**
 2→ * Backend Config -- deployment mode detection and endpoint resolution.
 3→ *
 4→ * Determines how the frontend connects to the backend based on environment:
 5→ * - Electron: localhost WS + HTTP via IPC-resolved port
 6→ * - Web-dev: localhost WS + HTTP via VITE_BACKEND_PORT
 7→ * - Web-production (relay): WS through relay.rundeus.com, HTTP tunneled over WS
 8→ *
 9→ * The resolved endpoints are cached after first call.
10→ */
11→
12→import { capabilities } from "@/platform/capabilities";
13→import { getBackendPort } from "./api.config";
14→
15→export type DeploymentMode = "electron" | "web-dev" | "web-production";
16→
17→/** Detect the current deployment mode. */
18→export function getDeploymentMode(): DeploymentMode {
19→  if (capabilities.ipcInvoke) return "electron";
20→  if (import.meta.env.VITE_BACKEND_PORT) return "web-dev";
21→  return "web-production";
22→}
23→
24→/** Whether the frontend is connecting through the cloud relay. */
25→export function isRelayMode(): boolean {
26→  return getDeploymentMode() === "web-production";
27→}
28→
29→export interface BackendEndpoints {
30→  wsUrl: string;
31→  apiBase: string;
32→}
33→
34→export const RELAY_BASE_URL =
35→  (import.meta.env.VITE_RELAY_URL as string | undefined) || "wss://relay.rundeus.com";
36→
37→let cachedEndpoints: BackendEndpoints | null = null;
38→/** The serverId that the cached endpoints were built for (relay mode only). */
39→let cachedRelayServerId: string | null = null;
40→
41→/**
42→ * Resolve the backend's WebSocket and HTTP base URLs.
43→ *
44→ * - Electron/web-dev: ws://localhost:{port}/ws + http://localhost:{port}/api
45→ * - Web-production: wss://relay.rundeus.com/api/servers/{serverId}/connect
46→ *   (HTTP goes through WS bridge, so apiBase is unused in relay mode)
47→ */
48→export async function resolveBackendEndpoints(serverId?: string): Promise<BackendEndpoints> {
49→  const mode = getDeploymentMode();
50→
51→  if (mode === "web-production") {
52→    // In relay mode, serverId comes from the URL (/s/{serverId}/...)
53→    // or can be passed explicitly.
54→    const id = serverId || getServerIdFromUrl();
55→    if (!id) {
56→      throw new Error("No server ID available for relay connection");
57→    }
58→    // Cache is per-serverId — invalidate if serverId changes (strict equality)
59→    if (cachedEndpoints && cachedRelayServerId === id) {
60→      return cachedEndpoints;
61→    }
62→    const encodedId = encodeURIComponent(id);
63→    cachedRelayServerId = id;
64→    cachedEndpoints = {
65→      wsUrl: `${RELAY_BASE_URL}/api/servers/${encodedId}/connect`,
66→      // In relay mode, HTTP is tunneled over WS — apiBase is a placeholder
67→      // that should never be used directly (client.ts intercepts requests).
68→      apiBase: `${RELAY_BASE_URL}/api/servers/${encodedId}`,
69→    };
70→    return cachedEndpoints;
71→  }
72→
73→  // Electron or web-dev: resolve local port
74→  if (cachedEndpoints) return cachedEndpoints;
75→
76→  const port = await getBackendPort();
77→  cachedEndpoints = {
78→    wsUrl: `ws://localhost:${port}/ws`,
79→    apiBase: `http://localhost:${port}/api`,
80→  };
81→  return cachedEndpoints;
82→}
83→
84→function invalidateEndpointCache(): void {
85→  cachedEndpoints = null;
86→  cachedRelayServerId = null;
87→}
88→
89→/** Extract serverId from the current URL pathname (/s/{serverId}/...). */
90→function getServerIdFromUrl(): string | null {
91→  const match = window.location.pathname.match(/^\/s\/([^/]+)/);
92→  return match ? match[1] : null;
93→}
94→

 1→export const DEFAULT_RELAY_URL = "wss://relay.rundeus.com";
 2→
 3→export function isLocalhost(ip: string | undefined): boolean {
 4→  if (!ip) return false;
 5→  return ip === "127.0.0.1" || ip === "::1" || ip === "::ffff:127.0.0.1" || ip === "localhost";
 6→}
 7→
 8→export function getClientIp(c: any): string | undefined {
 9→  return (
10→    (c.env as any)?.incoming?.socket?.remoteAddress ||
11→    c.req.header("x-forwarded-for")?.split(",")[0]?.trim() ||
12→    c.req.header("x-real-ip")
13→  );
14→}
