 1→// Deus Cloud Relay — Cloudflare Worker entry point.
 2→// Routes WebSocket upgrades to the RelayDO (one Durable Object per server).
 3→
 4→import { Hono } from "hono";
 5→import { cors } from "hono/cors";
 6→import { createMiddleware } from "hono/factory";
 7→import type { Bindings } from "./types";
 8→
 9→export { RelayDO } from "./relay-do";
10→
11→const app = new Hono<{ Bindings: Bindings }>();
12→
13→// CORS for web portal and local dev
14→app.use(
15→  "*",
16→  cors({
17→    origin: ["https://app.rundeus.com", "http://localhost:3000", "http://localhost:5173"],
18→    allowMethods: ["GET", "POST", "OPTIONS"],
19→    allowHeaders: ["Content-Type", "Authorization"],
20→  })
21→);
22→
23→// Middleware: validate serverId and attach DO stub to context
24→const withRelay = createMiddleware<{
25→  Bindings: Bindings;
26→  Variables: { stub: DurableObjectStub };
27→}>(async (c, next) => {
28→  const serverId = c.req.param("serverId");
29→  if (!serverId || !/^[a-z0-9]{4,8}$/i.test(serverId)) {
30→    return c.json({ error: "Invalid server ID" }, { status: 400 });
31→  }
32→  const id = c.env.RELAY.idFromName(serverId);
33→  c.set("stub", c.env.RELAY.get(id));
34→  await next();
35→});
36→
37→// Health check
38→app.get("/health", (c) =>
39→  c.json({
40→    status: "ok",
41→    timestamp: new Date().toISOString(),
42→    service: "deus-relay",
43→  })
44→);
45→
46→// Server tunnel — desktop server connects here to register with the relay
47→app.get("/api/servers/:serverId/tunnel", withRelay, async (c) => {
48→  const stub = c.get("stub");
49→  const tunnelUrl = new URL(c.req.url);
50→  tunnelUrl.pathname = "/tunnel";
51→  return stub.fetch(new Request(tunnelUrl, c.req.raw));
52→});
53→
54→// Client connect — remote web/mobile clients connect here
55→app.get("/api/servers/:serverId/connect", withRelay, async (c) => {
56→  const stub = c.get("stub");
57→  const connectUrl = new URL(c.req.url);
58→  connectUrl.pathname = "/connect";
59→  return stub.fetch(new Request(connectUrl, c.req.raw));
60→});
61→
62→// Pairing exchange — web portal exchanges a code for a device token
63→app.get("/api/servers/:serverId/pair", withRelay, async (c) => {
64→  const stub = c.get("stub");
65→  const pairUrl = new URL(c.req.url);
66→  pairUrl.pathname = "/pair";
67→  return stub.fetch(new Request(pairUrl, c.req.raw));
68→});
69→
70→// Server status — check if a server is online
71→app.get("/api/servers/:serverId/status", withRelay, async (c) => {
72→  const stub = c.get("stub");
73→  return stub.fetch(new Request(new URL("/status", c.req.url)));
74→});
75→
76→// Root
77→app.get("/", (c) =>
78→  c.json({
79→    name: "deus-relay",
80→    version: "0.1.0",
81→    docs: "https://app.rundeus.com",
82→  })
83→);
84→
85→export default app;
86→

 1→import Database from "better-sqlite3";
 2→import path from "path";
 3→import fs from "fs";
 4→import os from "os";
 5→import { SCHEMA_SQL, MIGRATIONS } from "@shared/schema";
 6→
 7→const DEFAULT_DB_PATH = path.join(
 8→  process.env.HOME || os.homedir(),
 9→  "Library/Application Support/com.deus.app/deus.db"
10→);
11→
12→const DB_PATH = process.env.DATABASE_PATH || DEFAULT_DB_PATH;
13→
14→let dbInstance: Database.Database | null = null;
15→
16→function initDatabase(): Database.Database {
17→  if (dbInstance) {
18→    return dbInstance;
19→  }
20→
21→  // Ensure parent directory exists (first launch)
22→  const dbDir = path.dirname(DB_PATH);
23→  if (!fs.existsSync(dbDir)) {
24→    fs.mkdirSync(dbDir, { recursive: true });
25→  }
26→
27→  console.log("Opening database:", DB_PATH);
28→
29→  try {
30→    dbInstance = new Database(DB_PATH);
31→    dbInstance.pragma("journal_mode = WAL");
32→    dbInstance.pragma("foreign_keys = ON");
33→    dbInstance.pragma("busy_timeout = 5000");
34→    dbInstance.pragma("optimize");
35→
36→    // Create all tables, indexes, and triggers (idempotent)
37→    dbInstance.exec(SCHEMA_SQL);
38→
39→    // Post-launch migrations: add new columns to existing tables.
40→    // Each ALTER TABLE may fail with "duplicate column" if already applied — skip those.
41→    for (const sql of MIGRATIONS) {
42→      try {
43→        dbInstance.exec(sql);
44→      } catch (e: unknown) {
45→        const msg = e instanceof Error ? e.message : "";
46→        if (!msg.includes("duplicate column") && !msg.includes("no such table")) throw e;
47→      }
48→    }
49→
50→    console.log("Database connected");
51→    return dbInstance;
52→  } catch (error) {
53→    console.error("Failed to open database:", error);
54→    throw error;
55→  }
56→}
57→
58→function getDatabase(): Database.Database {
59→  if (!dbInstance) {
60→    throw new Error("Database not initialized. Call initDatabase() first.");
61→  }
62→  return dbInstance;
63→}
64→
65→function closeDatabase(): void {
66→  if (dbInstance) {
67→    console.log("Closing database connection");
68→    dbInstance.pragma("optimize");
69→    dbInstance.close();
70→    dbInstance = null;
71→  }
72→}
73→
74→export { initDatabase, getDatabase, closeDatabase, DB_PATH };
