 30→function timeAgo(dateStr: string): string {
 31→  const diff = Date.now() - new Date(dateStr).getTime();
 32→  const minutes = Math.floor(diff / 60_000);
 33→  if (minutes < 1) return "just now";
 34→  if (minutes < 60) return `${minutes}m ago`;
 35→  const hours = Math.floor(minutes / 60);
 36→  if (hours < 24) return `${hours}h ago`;
 37→  const days = Math.floor(hours / 24);
 38→  return `${days}d ago`;
 39→}
 40→
 41→function getDeviceIcon(ua: string | null) {
 42→  if (!ua) return Monitor;
 43→  const lower = ua.toLowerCase();
 44→  if (lower.includes("mobile") || lower.includes("iphone") || lower.includes("android")) {
 45→    return Smartphone;
 46→  }
 47→  return Monitor;
 48→}
