119→/**
120→ * Connect Device Dialog -- shows QR code + code + countdown.
121→ * Code state is owned by the parent so it survives close/reopen.
122→ */
123→function ConnectDeviceDialog({
124→  open,
125→  onOpenChange,
126→  accessUrl,
127→  pairCode,
128→  countdown,
129→  isGenerating,
130→  onGenerate,
131→  devices,
132→  isDevicesLoaded,
133→}: {
134→  open: boolean;
135→  onOpenChange: (open: boolean) => void;
136→  accessUrl: string | null;
137→  pairCode: string | null;
138→  countdown: number;
139→  isGenerating: boolean;
140→  onGenerate: () => void;
141→  devices: PairedDevice[];
142→  isDevicesLoaded: boolean;
143→}) {
144→  const [prevDeviceIds, setPrevDeviceIds] = useState<Set<string>>(
145→    () => new Set(devices.map((d) => d.id))
146→  );
147→  const [showSuccess, setShowSuccess] = useState(false);
148→
149→  // Keep a stable ref of onOpenChange to avoid stale closures in setTimeout
150→  const onOpenChangeRef = useRef(onOpenChange);
151→  useEffect(() => {
152→    onOpenChangeRef.current = onOpenChange;
153→  }, [onOpenChange]);
154→
155→  // Generate code on first open if none exists
156→  useEffect(() => {
157→    if (open && !pairCode && !isGenerating) {
158→      onGenerate();
159→    }
160→    if (!open) {
161→      setShowSuccess(false);
162→    }
163→    // eslint-disable-next-line react-hooks/exhaustive-deps
164→  }, [open]);
165→
166→  // Detect successful pairing by comparing device IDs.
167→  // Gate on isDevicesLoaded to prevent false positives when the query resolves
168→  // from [] to existing devices after the dialog opens.
169→  useEffect(() => {
170→    const currentIds = new Set(devices.map((d) => d.id));
171→
172→    if (!isDevicesLoaded) {
173→      // Query hasn't resolved yet — just update the baseline, don't detect
174→      setPrevDeviceIds(currentIds);
175→      return;
176→    }
177→
178→    const hasNewDevice = devices.some((d) => !prevDeviceIds.has(d.id));
179→
180→    if (open && hasNewDevice) {
181→      setShowSuccess(true);
182→      const timer = setTimeout(() => onOpenChangeRef.current(false), 2000);
183→      setPrevDeviceIds(currentIds);
184→      return () => clearTimeout(timer);
185→    }
186→    setPrevDeviceIds(currentIds);
187→    return undefined;
188→    // eslint-disable-next-line react-hooks/exhaustive-deps
189→  }, [devices, open, isDevicesLoaded]);
190→
191→  const pairUrl = accessUrl && pairCode ? buildPairUrl(accessUrl, pairCode) : null;
192→  const minutes = Math.floor(countdown / 60);
193→  const isExpiringSoon = countdown > 0 && countdown < 120;
194→
195→  async function handleCopyCode() {
196→    if (!pairCode) return;
197→    try {
198→      await navigator.clipboard.writeText(pairCode);
199→      toast.success("Code copied");
200→    } catch {
201→      toast.error("Couldn't copy the code");
202→    }
203→  }
204→
205→  async function handleCopyLink() {
206→    if (!pairUrl) return;
207→    try {
208→      await navigator.clipboard.writeText(pairUrl);
209→      toast.success("Link copied");
210→    } catch {
211→      toast.error("Couldn't copy the link");
212→    }
213→  }
214→
215→  return (
216→    <Dialog open={open} onOpenChange={onOpenChange}>
217→      <DialogContent className="sm:max-w-md">
218→        {showSuccess ? (
219→          <div className="flex flex-col items-center gap-4 py-8">
220→            <div className="bg-success/10 flex size-16 items-center justify-center rounded-full">
221→              <Check className="text-success size-8" />
222→            </div>
223→            <div className="text-center">
224→              <DialogTitle className="text-lg font-semibold">Device Connected</DialogTitle>
225→              <DialogDescription className="text-muted-foreground mt-1 text-sm">
226→                You can now access your workspaces from this device.
227→              </DialogDescription>
228→            </div>
229→          </div>
230→        ) : (
231→          <>
232→            <DialogHeader className="text-center">
233→              <DialogTitle>Connect a Device</DialogTitle>
234→              <DialogDescription>
235→                Scan the QR code or enter the code on your other device.
236→              </DialogDescription>
237→            </DialogHeader>
238→
239→            <div className="flex flex-col items-center gap-5 pt-2">
240→              {/* QR Code -- hero element */}
241→              {pairUrl ? (
242→                <div className="rounded-xl bg-white p-3">
243→                  <QRCodeSVG value={pairUrl} size={180} level="M" />
244→                </div>
245→              ) : accessUrl ? (
246→                <div className="bg-muted/40 flex size-[204px] items-center justify-center rounded-xl">
247→                  <span className="text-muted-foreground text-sm">Generating...</span>
248→                </div>
249→              ) : (
250→                <div className="bg-muted/40 flex size-[204px] items-center justify-center rounded-xl">
251→                  <span className="text-muted-foreground px-4 text-center text-sm">
252→                    Waiting for connection...
253→                  </span>
254→                </div>
255→              )}
256→
257→              {/* Code display */}
258→              {pairCode ? (
259→                <p className="font-mono text-2xl font-bold tracking-wide">{pairCode}</p>
260→              ) : (
261→                <div className="bg-muted/40 h-8 w-40 animate-pulse rounded" />
262→              )}
263→
264→              {/* Action buttons — Copy Link is primary (higher conversion for web sharing) */}
265→              <div className="flex gap-2">
266→                <Button variant="default" size="sm" onClick={handleCopyLink} disabled={!pairUrl}>
267→                  <Link2 className="mr-1.5 size-3.5" />
268→                  Copy Link
269→                </Button>
270→                <Button variant="outline" size="sm" onClick={handleCopyCode} disabled={!pairCode}>
271→                  <Copy className="mr-1.5 size-3.5" />
272→                  Copy Code
273→                </Button>
274→              </div>
275→
276→              {/* Countdown + regenerate */}
277→              {countdown > 0 ? (
278→                <p
279→                  className={`text-xs ${isExpiringSoon ? "text-warning" : "text-muted-foreground"}`}
280→                >
281→                  {minutes >= 1
282→                    ? `Expires in ${minutes} ${minutes === 1 ? "minute" : "minutes"}`
283→                    : "Expiring soon"}
284→                </p>
285→              ) : pairCode === null && !isGenerating ? (
286→                <Button variant="ghost" size="sm" onClick={onGenerate}>
287→                  Generate new code
288→                </Button>
289→              ) : null}
290→            </div>
291→          </>
292→        )}
293→      </DialogContent>
294→    </Dialog>
295→  );
296→}
