  1→import { resolve, join } from "path";
  2→import { defineConfig } from "electron-vite";
  3→import react from "@vitejs/plugin-react";
  4→import tailwindcss from "@tailwindcss/vite";
  5→import svgr from "vite-plugin-svgr";
  6→import { readFileSync, existsSync } from "fs";
  7→import { tmpdir } from "os";
  8→import type { Plugin } from "vite";
  9→
 10→const pkg = JSON.parse(readFileSync(resolve(__dirname, "package.json"), "utf-8"));
 11→
 12→/**
 13→ * Vite plugin: serves the backend port file so Chrome tabs (without electronAPI)
 14→ * can discover the backend port during Electron dev mode.
 15→ *
 16→ * The Electron main process writes the port to a temp file after the backend starts.
 17→ * This middleware serves it at /__backend_port so the renderer can fetch it.
 18→ */
 19→function backendPortPlugin(): Plugin {
 20→  return {
 21→    name: "deus-backend-port",
 22→    configureServer(server) {
 23→      server.middlewares.use((req, res, next) => {
 24→        if (req.url === "/__backend_port") {
 25→          const portFile = join(tmpdir(), "deus-backend-port");
 26→          try {
 27→            if (existsSync(portFile)) {
 28→              const port = readFileSync(portFile, "utf-8").trim();
 29→              res.setHeader("Content-Type", "application/json");
 30→              res.setHeader("Access-Control-Allow-Origin", "*");
 31→              res.end(JSON.stringify({ port: parseInt(port, 10) }));
 32→              return;
 33→            }
 34→          } catch {
 35→            // Port file not readable — fall through to 503
 36→          }
 37→          res.statusCode = 503;
 38→          res.end(JSON.stringify({ error: "Backend not started yet" }));
 39→          return;
 40→        }
 41→        next();
 42→      });
 43→    },
 44→  };
 45→}
 46→
 47→export default defineConfig({
 48→  // ---------------------------------------------------------------------------
 49→  // Main process (apps/desktop/main/)
 50→  // ---------------------------------------------------------------------------
 51→  main: {
 52→    build: {
 53→      rollupOptions: {
 54→        input: {
 55→          index: resolve(__dirname, "apps/desktop/main/index.ts"),
 56→        },
 57→        external: ["better-sqlite3", "node-pty"],
 58→      },
 59→      outDir: "out/main",
 60→    },
 61→  },
 62→
 63→  // ---------------------------------------------------------------------------
 64→  // Preload scripts (apps/desktop/preload/)
 65→  // ---------------------------------------------------------------------------
 66→  preload: {
 67→    build: {
 68→      rollupOptions: {
 69→        input: {
 70→          index: resolve(__dirname, "apps/desktop/preload/index.ts"),
 71→          "browser-preload": resolve(__dirname, "apps/desktop/preload/browser-preload.ts"),
 72→        },
 73→      },
 74→      outDir: "out/preload",
 75→    },
 76→  },
 77→
 78→  // ---------------------------------------------------------------------------
 79→  // Renderer (apps/web/) — React app
 80→  // ---------------------------------------------------------------------------
 81→  renderer: {
 82→    root: resolve(__dirname, "apps/web"),
 83→    plugins: [react(), svgr(), tailwindcss(), backendPortPlugin()],
 84→    define: {
 85→      __APP_VERSION__: JSON.stringify(pkg.version),
 86→    },
 87→    resolve: {
