 90→        "@/app": resolve(__dirname, "apps/web/src/app"),
 91→        "@/features": resolve(__dirname, "apps/web/src/features"),
 92→        "@/platform": resolve(__dirname, "apps/web/src/platform"),
 93→        "@/shared": resolve(__dirname, "apps/web/src/shared"),
